import { describe, expect, it } from 'vitest';
import { MeshRuntime } from './mesh-runtime.js';
import { MeshEventFanout } from './sse-fanout.js';

describe('mesh-runtime', () => {
  it('fails validation for host/service when meshStationUrls is empty', () => {
    const rt = new MeshRuntime(process.cwd());
    const hostCfg = rt.setConfig({ meshBackend: 'host', meshStationUrls: '' });
    const hostInvalid = rt.validateConfig(hostCfg);
    expect(hostInvalid?.ok).toBe(false);
    expect(hostInvalid?.code).toBe('MESH_STATION_URLS_REQUIRED');

    const serviceCfg = rt.setConfig({ meshBackend: 'service', meshStationUrls: '' });
    const serviceInvalid = rt.validateConfig(serviceCfg);
    expect(serviceInvalid?.ok).toBe(false);
    expect(serviceInvalid?.code).toBe('MESH_STATION_URLS_REQUIRED');
  });

  it('fails validation for native when aeon-monitor is not executable', () => {
    const rt = new MeshRuntime(process.cwd());
    const cfg = rt.setConfig({
      meshBackend: 'native',
      gnosisAeonMonitorBin: '/definitely/not/executable/aeon-monitor',
    });
    const invalid = rt.validateConfig(cfg);
    expect(invalid?.ok).toBe(false);
    expect(invalid?.code).toBe('AEON_MONITOR_NOT_EXECUTABLE');
  });

  it('returns stable envelope for stop when not running', () => {
    const rt = new MeshRuntime(process.cwd());
    const r = rt.stopMesh();
    expect(r).toMatchObject({
      ok: false,
      code: 'MESH_NOT_RUNNING',
    });
  });

  it('start returns guardrail envelope when config is invalid', () => {
    const rt = new MeshRuntime(process.cwd());
    rt.setConfig({ meshBackend: 'host', meshStationUrls: '' });
    const r = rt.startMesh([], new MeshEventFanout());
    expect(r).toMatchObject({
      ok: false,
      code: 'MESH_STATION_URLS_REQUIRED',
    });
  });
});
